using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    #region AddItem

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _sut.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(1, _sut.Items.Count);
        Assert.AreEqual("SKU-001", _sut.Items[0].Sku);
        Assert.AreEqual(2, _sut.Items[0].Quantity);
        Assert.AreEqual(9.99m, _sut.Items[0].Price);
    }

    [TestMethod]
    public void AddItem_DuplicateSku_IncrementsQuantity()
    {
        _sut.AddItem("SKU-001", 2, 5.00m);
        _sut.AddItem("SKU-001", 3, 5.00m);

        Assert.AreEqual(1, _sut.Items.Count);
        Assert.AreEqual(5, _sut.Items[0].Quantity);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllAppearInCart()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.AddItem("B", 2, 20m);

        Assert.AreEqual(2, _sut.Items.Count);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-001", quantity, 10m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-001", 1, -1m));
    }

    #endregion

    #region RemoveItem

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-001", 1, 10m);

        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(0, _sut.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void RemoveItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(sku!));
    }

    #endregion

    #region CalculateTotal

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsPriceTimesQuantity()
    {
        _sut.AddItem("SKU-001", 3, 10.00m);

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        _sut.AddItem("A", 2, 5.00m);  // 10
        _sut.AddItem("B", 1, 20.00m); // 20

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_ExcludesRemovedItem()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.AddItem("B", 1, 20m);
        _sut.RemoveItem("A");

        Assert.AreEqual(20m, _sut.CalculateTotal());
    }

    #endregion

    #region ApplyCoupon

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        _sut.AddItem("SKU-001", 1, 100m);
        _sut.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _sut.CalculateTotal());
        Assert.AreEqual("SAVE10", _sut.AppliedCoupon);
    }

    [TestMethod]
    public void ApplyCoupon_Half_Applies50PercentDiscount()
    {
        _sut.AddItem("SKU-001", 2, 50m);
        _sut.ApplyCoupon("HALF");

        Assert.AreEqual(50.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void ApplyCoupon_NullOrWhiteSpace_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void CalculateTotal_NoCoupon_ReturnsFullPrice()
    {
        _sut.AddItem("SKU-001", 1, 100m);

        Assert.AreEqual(100m, _sut.CalculateTotal());
        Assert.IsNull(_sut.AppliedCoupon);
    }

    #endregion
}

