    }

    [TestMethod]
    public void AddItem_DuplicateSku_IncrementsQuantity()
    {
        _sut.AddItem("SKU-001", 2, 5.00m);
        _sut.AddItem("SKU-001", 3, 5.00m);

        Assert.AreEqual(1, _sut.Items.Count);
        Assert.AreEqual(5, _sut.Items[0].Quantity);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllAppearInCart()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.AddItem("B", 2, 20m);

        Assert.AreEqual(2, _sut.Items.Count);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
