    public void ApplyCoupon_Half_Applies50PercentDiscount()
    {
        _sut.AddItem("SKU-001", 2, 50m);
        _sut.ApplyCoupon("HALF");

        Assert.AreEqual(50.00m, _sut.CalculateTotal());
    }

